def majority_vote(labels: List[str]) -> Optional[str]:
    if not labels:
        return None
    counts: Dict[str, int] = {}
    for l in labels:
        counts[l] = counts.get(l, 0) + 1
    max_count = max(counts.values())
    winners = [k for k, v in counts.items() if v == max_count]
    winners.sort()
    return winners[0]


def fetch_aggregated_label(conn: sqlite3.Connection, dataset_id: str, image_id: str) -> Optional[str]:
    cur = conn.execute(
        "SELECT label FROM annotations WHERE dataset_id=? AND image_id=?",
        (dataset_id, image_id),
    )
    labels = [r["label"] for r in cur.fetchall()]
    return majority_vote(labels)


def fetch_all_aggregated_labels(conn: sqlite3.Connection, dataset_id: str) -> List[Tuple[str, str]]:
    cur = conn.execute("SELECT id FROM images WHERE dataset_id=?", (dataset_id,))
    image_ids = [r["id"] for r in cur.fetchall()]
    out: List[Tuple[str, str]] = []
    for image_id in image_ids:
        label = fetch_aggregated_label(conn, dataset_id, image_id)
        if label is not None:
            out.append((image_id, label))
    return out


def ensure_dataset(conn: sqlite3.Connection, dataset_id: str) -> sqlite3.Row:
    cur = conn.execute("SELECT * FROM datasets WHERE id=?", (dataset_id,))
    row = cur.fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="dataset_not_found")
    return row


def ensure_image(conn: sqlite3.Connection, dataset_id: str, image_id: str) -> sqlite3.Row:
    cur = conn.execute("SELECT * FROM images WHERE id=? AND dataset_id=?", (image_id, dataset_id))
    row = cur.fetchone()
    if not row:
        raise HTTPException(status_code=404, detail="image_not_found")
    return row


