@app.post("/datasets/{dataset_id}/images")
async def upload_image(dataset_id: str, file: UploadFile = File(...), orig_filename: Optional[str] = Form(None)):
    image_id = str(uuid.uuid4())
    content = await file.read()
    try:
        img = Image.open(io.BytesIO(content)).convert("RGB")
        width, height = img.size
    except Exception:
        raise HTTPException(status_code=400, detail="invalid_image")

    ext = os.path.splitext(file.filename or "")[1].lower()
    if ext not in [".jpg", ".jpeg", ".png", ".bmp", ".webp"]:
        ext = ".jpg"
    filename = f"{image_id}{ext}"
    path = os.path.join(IMAGES_DIR, filename)
    try:
        img.save(path)
    except Exception:
        raise HTTPException(status_code=500, detail="failed_to_store_image")

    with DB_LOCK:
        conn = get_conn()
        try:
            ensure_dataset(conn, dataset_id)
            conn.execute(
                "INSERT INTO images(id, dataset_id, filename, orig_filename, width, height, created_at) VALUES(?,?,?,?,?,?,?)",
                (image_id, dataset_id, filename, orig_filename or file.filename, width, height, utcnow_iso()),
            )
            conn.commit()
        finally:
            conn.close()

    return {"image_id": image_id, "dataset_id": dataset_id, "filename": filename, "width": width, "height": height}


