class ImageLabelDataset(Dataset):
    def __init__(self, items: List[Tuple[str, int]], image_paths: Dict[str, str], transform):
        self.items = items
        self.image_paths = image_paths
        self.transform = transform

    def __len__(self):
        return len(self.items)

    def __getitem__(self, idx: int):
        image_id, y = self.items[idx]
        path = self.image_paths[image_id]
        img = Image.open(path).convert("RGB")
        x = self.transform(img)
        return x, y


def train_classifier(
    dataset_id: str,
    train_id: str,
    epochs: int,
    batch_size: int,
    lr: float,
    device: str,
) -> Dict[str, Any]:
    with DB_LOCK:
        conn = get_conn()
        try:
            ensure_dataset(conn, dataset_id)
            cur = conn.execute("SELECT id, filename FROM images WHERE dataset_id=?", (dataset_id,))
            img_rows = cur.fetchall()
            image_paths = {r["id"]: os.path.join(IMAGES_DIR, r["filename"]) for r in img_rows}
            aggregated = fetch_all_aggregated_labels(conn, dataset_id)
        finally:
            conn.close()

    if not aggregated:
        raise RuntimeError("no_aggregated_labels")

    labels = [l for _, l in aggregated]
    classes = sorted(list(set(labels)))
    class_to_idx = {c: i for i, c in enumerate(classes)}

    items = [(image_id, class_to_idx[label]) for image_id, label in aggregated if image_id in image_paths]
    if not items:
        raise RuntimeError("no_labeled_images_on_disk")

    transform = T.Compose([
        T.Resize((224, 224)),
        T.ToTensor(),
        T.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])

    ds = ImageLabelDataset(items, image_paths, transform)
    dl = DataLoader(ds, batch_size=batch_size, shuffle=True, num_workers=0, pin_memory=False)

    num_classes = len(classes)
    model = models.resnet18(weights=None)
    model.fc = nn.Linear(model.fc.in_features, num_classes)
    model.to(device)

    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=lr)

    model.train()
    losses = []
    t0 = time.time()
    for epoch in range(epochs):
        running = 0.0
        n = 0
        for xb, yb in dl:
            xb = xb.to(device)
            yb = yb.to(device)
            optimizer.zero_grad(set_to_none=True)
            logits = model(xb)
            loss = criterion(logits, yb)
            loss.backward()
            optimizer.step()
            running += float(loss.item()) * xb.size(0)
            n += xb.size(0)
        epoch_loss = running / max(1, n)
        losses.append(epoch_loss)

    duration_s = time.time() - t0

    model_path = os.path.join(MODELS_DIR, f"{dataset_id}_{train_id}.pt")
    payload = {
        "state_dict": model.state_dict(),
        "classes": classes,
        "arch": "resnet18",
        "input_size": [224, 224],
        "normalize": {"mean": [0.485, 0.456, 0.406], "std": [0.229, 0.224, 0.225]},
        "trained_at": utcnow_iso(),
    }
    torch.save(payload, model_path)

    metrics = {
        "train_loss": losses[-1] if losses else None,
        "loss_curve": losses,
        "epochs": epochs,
        "batch_size": batch_size,
        "lr": lr,
        "num_samples": len(ds),
        "duration_s": duration_s,
        "device": device,
    }
    return {"model_path": model_path, "classes": classes, "metrics": metrics, "num_images": len(image_paths), "num_labeled_images": len(ds), "num_classes": num_classes}


def update_training(conn: sqlite3.Connection, training_id: str, **fields):
    if not fields:
        return
    keys = []
    vals = []
    for k, v in fields.items():
        keys.append(f"{k}=?")
        vals.append(v)
    vals.append(training_id)
    conn.execute(f"UPDATE trainings SET {', '.join(keys)} WHERE id=?", vals)


def training_worker(training_id: str, dataset_id: str, epochs: int, batch_size: int, lr: float, device: str):
    with DB_LOCK:
        conn = get_conn()
        try:
            update_training(conn, training_id, status="running", updated_at=utcnow_iso())
            conn.commit()
        finally:
            conn.close()

    try:
        result = train_classifier(dataset_id, training_id, epochs, batch_size, lr, device)
        with DB_LOCK:
            conn = get_conn()
            try:
                update_training(
                    conn,
                    training_id,
                    status="completed",
                    model_path=result["model_path"],
                    classes_json=json.dumps(result["classes"]),
                    metrics_json=json.dumps(result["metrics"]),
                    num_images=result["num_images"],
                    num_labeled_images=result["num_labeled_images"],
                    num_classes=result["num_classes"],
                    updated_at=utcnow_iso(),
                    error=None,
                )
                conn.commit()
            finally:
                conn.close()
    except Exception as e:
        with DB_LOCK:
            conn = get_conn()
            try:
                update_training(
                    conn,
                    training_id,
                    status="failed",
                    error=str(e),
                    updated_at=utcnow_iso(),
                )
                conn.commit()
            finally:
                conn.close()


@app.post("/datasets/{dataset_id}/train")
def start_training(
    dataset_id: str,
    epochs: int = Form(3),
    batch_size: int = Form(16),
    lr: float = Form(1e-3),
    device: Optional[str] = Form(None),
):
    if device is None:
        device = "cuda" if torch.cuda.is_available() else "cpu"

    training_id = str(uuid.uuid4())
    with DB_LOCK:
        conn = get_conn()
        try:
            ensure_dataset(conn, dataset_id)
            cur = conn.execute("SELECT COUNT(*) AS n FROM images WHERE dataset_id=?", (dataset_id,))
            num_images = int(cur.fetchone()["n"])
            cur = conn.execute(
                "SELECT COUNT(DISTINCT image_id) AS n FROM annotations WHERE dataset_id=?",
                (dataset_id,),
            )
            num_labeled_images = int(cur.fetchone()["n"])
            conn.execute(
                "INSERT INTO trainings(id, dataset_id, status, num_images, num_labeled_images, num_classes, model_path, classes_json, metrics_json, error, created_at, updated_at) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)",
                (
                    training_id,
                    dataset_id,
                    "queued",
                    num_images,
                    num_labeled_images,
                    0,
                    None,
                    None,
                    None,
                    None,
                    utcnow_iso(),
                    utcnow_iso(),
                ),
            )
            conn.commit()
        finally:
            conn.close()

    th = threading.Thread(
        target=training_worker,
        args=(training_id, dataset_id, int(epochs), int(batch_size), float(lr), str(device)),
        daemon=True,
    )
    th.start()

    return {"training_id": training_id, "dataset_id": dataset_id, "status": "queued", "device": device}


@app.get("/datasets/{dataset_id}/train/{training_id}")
def get_training_status(dataset_id: str, training_id: str):
    with DB_LOCK:
        conn = get_conn()
        try:
            ensure_dataset(conn, dataset_id)
            cur = conn.execute(
                "SELECT * FROM trainings WHERE id=? AND dataset_id=?",
                (training_id, dataset_id),
            )
            row = cur.fetchone()
            if not row:
                raise HTTPException(status_code=404, detail="training_not_found")
            d = dict(row)
            if d.get("classes_json"):
                d["classes"] = json.loads(d["classes_json"])
            if d.get("metrics_json"):
                d["metrics"] = json.loads(d["metrics_json"])
            d.pop("classes_json", None)
            d.pop("metrics_json", None)
        finally:
            conn.close()
    return d


@app.get("/datasets/{dataset_id}/train")
def list_trainings(dataset_id: str, limit: int = Query(20, ge=1, le=200), offset: int = Query(0, ge=0)):
    with DB_LOCK:
        conn = get_conn()
        try:
            ensure_dataset(conn, dataset_id)
            cur = conn.execute(
                "SELECT * FROM trainings WHERE dataset_id=? ORDER BY created_at DESC LIMIT ? OFFSET ?",
                (dataset_id, limit, offset),
            )
            trainings = []
            for r in cur.fetchall():
                d = dict(r)
                if d.get("classes_json"):
                    d["classes"] = json.loads(d["classes_json"])
                if d.get("metrics_json"):
                    d["metrics"] = json.loads(d["metrics_json"])
                d.pop("classes_json", None)
                d.pop("metrics_json", None)
                trainings.append(d)
        finally:
            conn.close()
    return {"trainings": trainings, "limit": limit, "offset": offset}


